 549	#[derive(Clone, Debug, PartialEq, Eq)]
 550	struct OpenAiCodexInvocation {
 551	    session_launcher: PathBuf,
 552	    command: PathBuf,
 553	    arguments: Vec<OsString>,
 554	    timeout: ProviderCallTimeout,
 555	}
 556	
 557	impl OpenAiCodexInvocation {
 558	    fn from_request(
 559	        session_launcher: &Path,
 560	        command: &Path,
 561	        timeout: ProviderCallTimeout,
 562	        request: ProviderCallRequest,
 563	    ) -> Result<Self, Error> {
 564	        if request.provider_name().as_str() != "openai-codex" {
 565	            return Err(Error::ProviderCall(
 566	                "OpenAI Codex client requires provider openai-codex".to_owned(),
 567	            ));
 568	        }
 569	        let mut arguments = vec![
 570	            OsString::from("exec"),
 571	            OsString::from("--ephemeral"),
 572	            OsString::from("--skip-git-repo-check"),
 573	            OsString::from("--ignore-rules"),
 574	            OsString::from("--sandbox"),
 575	            OsString::from("read-only"),
 576	            OsString::from("--model"),
 577	            OsString::from(request.model_name().as_str()),
 578	        ];
 579	        if let Some(reasoning_effort) = request.reasoning_effort() {
 580	            arguments.push(OsString::from("--config"));
 581	            arguments.push(OsString::from(format!(
 582	                "model_reasoning_effort=\"{}\"",
 583	                reasoning_effort.as_str()
 584	            )));
 585	        }
 586	        arguments.push(OsString::from(Self::prompt_from_messages(
 587	            request.messages(),
 588	        )));
 589	        Ok(Self {
 590	            session_launcher: session_launcher.to_path_buf(),
 591	            command: command.to_path_buf(),
 592	            arguments,
 593	            timeout,
 594	        })
 595	    }
 596	
 597	    fn prompt_from_messages(messages: &[ProviderMessage]) -> String {
 598	        messages
 599	            .iter()
 600	            .map(|message| match message.role() {
 601	                ProviderMessageRole::System => format!("[system]\n{}", message.text()),
 602	                ProviderMessageRole::User => format!("[user]\n{}", message.text()),
 603	                ProviderMessageRole::Assistant => format!("[assistant]\n{}", message.text()),
 604	            })
 605	            .collect::<Vec<_>>()
 606	            .join("\n\n")
 607	    }
 608	
 609	    fn execute(self) -> Result<ProviderCallReply, Error> {
 610	        let output = CodexChildProcess::new(
 611	            &self.session_launcher,
 612	            &self.command,
 613	            self.arguments,
 614	            self.timeout,
 615	        )
 616	        .execute()?;
 617	        if !output.status.success() {
 618	            return Err(Error::ProviderCommandExited);
 619	        }
 620	        let output_text =
 621	            String::from_utf8(output.stdout).map_err(|_| Error::ProviderCommandNonUtf8Output)?;
 622	        if output_text.trim().is_empty() {
 623	            return Err(Error::ProviderCommandEmptyOutput);
 624	        }
 625	        Ok(ProviderCallReply::new(output_text, Vec::new()))
 626	    }
 627	}
 628	
 629	struct CodexChildProcess<'command> {
 630	    session_launcher: &'command Path,
 631	    command: &'command Path,
 632	    arguments: Vec<OsString>,
 633	    timeout: ProviderCallTimeout,
 634	}
 635	
 636	impl<'command> CodexChildProcess<'command> {
 637	    fn new(
 638	        session_launcher: &'command Path,
 639	        command: &'command Path,
 640	        arguments: Vec<OsString>,
 641	        timeout: ProviderCallTimeout,
 642	    ) -> Self {
 643	        Self {
 644	            session_launcher,
 645	            command,
 646	            arguments,
 647	            timeout,
 648	        }
 649	    }
 650	
 651	    fn execute(self) -> Result<std::process::Output, Error> {
 652	        let output_file =
 653	            tempfile::NamedTempFile::new().map_err(|_| Error::ProviderCommandUnavailable)?;
 654	        let output_path = output_file.path().to_path_buf();
 655	        let stdout = output_file
 656	            .reopen()
 657	            .map_err(|_| Error::ProviderCommandUnavailable)?;
 658	        let mut child = Command::new(self.session_launcher)
 659	            .arg(self.command)
 660	            .args(&self.arguments)
 661	            .stdout(Stdio::from(stdout))
 662	            .stderr(Stdio::null())
 663	            .spawn()
 664	            .map_err(|_| Error::ProviderCommandUnavailable)?;
 665	        let deadline = Instant::now() + self.timeout.duration();
 666	        loop {
 667	            if let Some(status) = child
 668	                .try_wait()
 669	                .map_err(|_| Error::ProviderCommandUnavailable)?
 670	            {
 671	                let output =
 672	                    std::fs::read(&output_path).map_err(|_| Error::ProviderCommandUnavailable)?;
 673	                return Ok(std::process::Output {
 674	                    status,
 675	                    stdout: output,
 676	                    stderr: Vec::new(),
 677	                });
 678	            }
 679	            if Instant::now() >= deadline {
 680	                self.terminate_process_group(&mut child)?;
 681	                return Err(Error::ProviderCommandTimedOut);
 682	            }
 683	            thread::sleep(Duration::from_millis(10));
 684	        }
 685	    }
 686	
 687	    fn terminate_process_group(&self, child: &mut std::process::Child) -> Result<(), Error> {
 688	        let process_group = Pid::from_raw(-(child.id() as i32));
 689	        kill(process_group, Signal::SIGTERM)
 690	            .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
 691	        let grace_deadline = Instant::now() + Duration::from_millis(100);
 692	        while Instant::now() < grace_deadline {
 693	            if child
 694	                .try_wait()
 695	                .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?
 696	                .is_some()
 697	            {
 698	                return Ok(());
 699	            }
 700	            thread::sleep(Duration::from_millis(10));
 701	        }
 702	        kill(process_group, Signal::SIGKILL)
 703	            .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
 704	        child
 705	            .wait()
 706	            .map_err(|_| Error::ProviderProcessGroupTeardownFailed)?;
 707	        Ok(())
 708	    }
 709	}
