 496	impl OpenAiCodexProviderClient {
 497	    pub fn new(
 498	        session_launcher: impl Into<PathBuf>,
 499	        command: impl Into<PathBuf>,
 500	        timeout: ProviderCallTimeout,
 501	    ) -> Self {
 502	        Self {
 503	            session_launcher: session_launcher.into(),
 504	            command: command.into(),
