 509	    fn verify_authorization(
 510	        &self,
 511	        authorization: &ResolvedProviderAuthorization,
 512	    ) -> Result<(), Error> {
 513	        let ResolvedProviderAuthorization::ExternalSession(reference) = authorization else {
 514	            return Err(Error::ProviderAuthorizationUnsupported);
 515	        };
 516	        if reference.as_str() != CODEX_AMBIENT_SESSION_REFERENCE {
 517	            return Err(Error::ProviderAuthorizationReferenceUnsupported);
 518	        }
 519	        let output = CodexChildProcess::new(
 520	            &self.session_launcher,
 521	            &self.command,
 522	            vec![OsString::from("login"), OsString::from("status")],
 523	            self.timeout,
 524	        )
 525	        .execute()?;
 526	        if !output.status.success() {
 527	            return Err(Error::ProviderAuthorizationUnsupported);
 528	        }
 529	        Ok(())
 530	    }
