 911	    struct FakeCodex {
 912	        temporary: tempfile::TempDir,
 913	        command: PathBuf,
 914	        transcript: PathBuf,
 915	        descendant_sentinel: PathBuf,
 916	    }
 917	
 918	    impl FakeCodex {
 919	        fn new(action: &str) -> Self {
 920	            use std::os::unix::fs::PermissionsExt;
 921	
 922	            let temporary = tempfile::TempDir::new().unwrap();
 923	            let command = temporary.path().join("codex");
 924	            let transcript = temporary.path().join("transcript");
 925	            let descendant_sentinel = temporary.path().join("descendant-sentinel");
 926	            let interpreter = if Path::new("/bin/sh").exists() {
 927	                "/bin/sh".to_owned()
 928	            } else {
 929	                std::env::var("SHELL").unwrap_or_else(|_| "sh".to_owned())
 930	            };
 931	            let script = format!(
 932	                "#!{interpreter}\nprintf '%s\\n' \"$@\" >> '{}'\nif [ \"$1 $2\" = 'login status' ]; then exit 0; fi\ncase '{}' in\naccept) printf 'Accept\\n' ;;\nmalformed) printf 'not-a-nota-verdict\\n' ;;\nempty) : ;;\nnonutf8) printf '\\377' ;;\nnonzero) exit 9 ;;\nhang) sleep 5 ;;\ndescendant) (sleep 0.2; touch '{}') & sleep 5 ;;\nesac\n",
 933	                transcript.display(),
 934	                action,
 935	                descendant_sentinel.display()
 936	            );
 937	            std::fs::write(&command, script).unwrap();
 938	            let mut permissions = std::fs::metadata(&command).unwrap().permissions();
 939	            permissions.set_mode(0o700);
 940	            std::fs::set_permissions(&command, permissions).unwrap();
 941	            Self {
 942	                temporary,
 943	                command,
 944	                transcript,
 945	                descendant_sentinel,
 946	            }
 947	        }
 948	
 949	        fn client(&self, timeout: u64) -> OpenAiCodexProviderClient {
 950	            let _keep = self.temporary.path();
 951	            OpenAiCodexProviderClient::new(
 952	                "setsid",
 953	                &self.command,
 954	                ProviderCallTimeout::from_milliseconds(timeout).unwrap(),
 955	            )
 956	        }
 957	
 958	        fn transcript(&self) -> String {
 959	            std::fs::read_to_string(&self.transcript).unwrap()
 960	        }
 961	
 962	        fn descendant_survived(&self) -> bool {
 963	            std::thread::sleep(Duration::from_millis(300));
 964	            self.descendant_sentinel.exists()
 965	        }
 966	    }
